AND (email LIKE CONCAT('%', #{keyword}, '%') OR nickname LIKE CONCAT('%', #{keyword}, '%') OR `쉼표번호` LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
ORDER BY created_at DESC LIMIT #{size} OFFSET #{offset}

